import { useState } from "react"
import { motion, AnimatePresence } from "framer-motion"
import { Loader2, Check, Rocket } from "lucide-react"
import confetti from "canvas-confetti"
import { cn } from "@/lib/utils"

export function FoundersPitButton({ 
  text = {
    idle: "🚀 Founders Pit 2026",
    saving: "Processing...",
    saved: "Success! 🎉"
  },
  className,
  onSave,
  onClick
}) {
  const [status, setStatus] = useState("idle")
  const [bounce, setBounce] = useState(false)

  const handleClick = async () => {
    if (status === "idle") {
      setStatus("saving")
      try {
        if (onSave) {
          await onSave()
        } else {
          // Default simulation
          await new Promise(resolve => setTimeout(resolve, 2000))
        }
        setStatus("saved")
        setBounce(true)
        
        // Confetti with brand colors
        confetti({
          particleCount: 100,
          spread: 70,
          origin: { y: 0.6 },
          colors: ["#05B1DE", "#0597C7", "#047DAA", "#06C7E8", "#0582D4"],
          shapes: ["star", "circle"],
        })
        
        setTimeout(() => {
          setStatus("idle")
          setBounce(false)
        }, 2000)
      } catch (error) {
        setStatus("idle")
        console.error("Action failed:", error)
      }
    }
  }

  const buttonVariants = {
    idle: {
      backgroundImage: "linear-gradient(to right, rgba(5, 177, 222, 0.7), rgba(5, 151, 199, 0.7), rgba(4, 125, 170, 0.7))",
      scale: 1,
    },
    saving: {
      backgroundImage: "linear-gradient(to right, rgba(59, 130, 246, 0.8), rgba(37, 99, 235, 0.8))",
      scale: 1,
    },
    saved: {
      backgroundImage: "linear-gradient(to right, rgba(34, 197, 94, 0.8), rgba(22, 163, 74, 0.8))",
      scale: [1, 1.1, 1],
      transition: {
        duration: 0.2,
        times: [0, 0.5, 1],
      },
    },
  }

  return (
    <div className="relative">
      <motion.button
        onClick={handleClick}
        animate={status}
        variants={buttonVariants}
        className={cn(
          "relative text-sm xl:text-base px-4 xl:px-5 py-2 text-white font-bold transition-all duration-300 rounded-lg border-2 border-[#05B1DE]/50 backdrop-blur-md overflow-hidden group hover:scale-110 hover:shadow-2xl hover:shadow-cyan-500/40",
          className
        )}
        whileHover={status === "idle" ? { scale: 1.11 } : {}}
        whileTap={status === "idle" ? { scale: 0.95 } : {}}
      >
        {/* Shine effect on hover */}
        <span className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent transform -skew-x-12 scale-x-0 group-hover:scale-x-100 transition-transform duration-700 origin-left"></span>
        
        {/* Subtle glow effect */}
        <span className="absolute inset-0 rounded-lg opacity-0 group-hover:opacity-50 transition-opacity duration-300 bg-gradient-to-r from-[#05B1DE]/15 via-[#0597C7]/10 to-[#047DAA]/15 animate-pulse"></span>
        
        {/* Outer subtle glow */}
        <span className={cn(
          "absolute -inset-0.5 rounded-lg opacity-0 transition-opacity duration-300 blur-md bg-gradient-to-r from-[#05B1DE] via-[#0597C7] to-[#047DAA]",
          status !== "idle" ? "hidden" : "group-hover:opacity-20 animate-pulse"
        )} style={{animationDelay: '0.5s'}}></span>
        
        <span className="relative flex items-center justify-center gap-2">
          <AnimatePresence mode="wait">
            {status === "idle" && (
              <motion.span
                key="idle"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
              >
                {text.idle}
              </motion.span>
            )}
            {status === "saving" && (
              <motion.div
                key="saving"
                className="flex items-center gap-2"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
              >
                <motion.span
                  animate={{ rotate: 360 }}
                  transition={{
                    repeat: Number.POSITIVE_INFINITY,
                    duration: 1,
                    ease: "linear",
                  }}
                >
                  <Loader2 className="w-4 h-4" />
                </motion.span>
                {text.saving}
              </motion.div>
            )}
            {status === "saved" && (
              <motion.div
                key="saved"
                className="flex items-center gap-2"
                initial={{ opacity: 0, scale: 0.5 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0 }}
              >
                <Check className="w-4 h-4" />
                {text.saved}
              </motion.div>
            )}
          </AnimatePresence>
        </span>
      </motion.button>
    </div>
  )
}
